const input = $input.first().json;
const action = input.action || 'search_exercises';

const BASE = 'https://wger.de/api/v2';
const UA = 'n8n-claw/1.0 (github.com/freddy-schuetz/n8n-claw)';

async function api(path) {
  return await helpers.httpRequest({
    method: 'GET',
    url: BASE + path,
    headers: { 'User-Agent': UA, 'Accept': 'application/json' },
    timeout: 15000,
    json: true
  });
}

function langCode(lang) {
  // wger language IDs: 1=de, 2=en, 4=ru, 5=es, 7=bg, 8=sv, 9=nl, 12=el, 13=cs, 14=ar, 15=tr, 16=fr, 17=pt, 18=it, 19=ko, 20=zh, 21=hr, 22=hu, 23=ja, 24=he, 26=lt, 27=pl, 28=da
  const m = { de: 1, en: 2, es: 5, fr: 16, it: 18, pt: 17, nl: 9 };
  if (typeof lang === 'number') return lang;
  return m[(lang || 'en').toLowerCase()] || 2;
}

function pickTranslation(translations, languageId) {
  if (!Array.isArray(translations) || translations.length === 0) return null;
  return translations.find(t => t.language === languageId)
      || translations.find(t => t.language === 2)
      || translations[0];
}

function stripHtml(s) {
  if (!s) return '';
  return String(s).replace(/<[^>]+>/g, ' ').replace(/&nbsp;/g, ' ').replace(/&amp;/g, '&').replace(/\s+/g, ' ').trim();
}

function formatExerciseSummary(ex, langId, idx) {
  const tr = pickTranslation(ex.translations, langId) || {};
  const name = tr.name || 'Unnamed';
  const cat = ex.category && ex.category.name ? ex.category.name : '?';
  const muscles = (ex.muscles || []).map(m => m.name_en || m.name).filter(Boolean).join(', ');
  const equip = (ex.equipment || []).map(e => e.name).filter(Boolean).join(', ') || 'none';
  const prefix = idx != null ? (idx + 1) + '. ' : '';
  let out = prefix + name + ' [#' + ex.id + ']';
  out += '\n   Category: ' + cat + ' | Equipment: ' + equip;
  if (muscles) out += '\n   Primary muscles: ' + muscles;
  return out;
}

function formatExerciseFull(ex, langId) {
  const tr = pickTranslation(ex.translations, langId) || {};
  const name = tr.name || 'Unnamed';
  const desc = stripHtml(tr.description || '');
  const aliases = Array.isArray(tr.aliases) ? tr.aliases.map(a => a.alias).filter(Boolean) : [];
  const cat = ex.category && ex.category.name ? ex.category.name : '?';
  const primary = (ex.muscles || []).map(m => m.name_en || m.name).filter(Boolean);
  const secondary = (ex.muscles_secondary || []).map(m => m.name_en || m.name).filter(Boolean);
  const equip = (ex.equipment || []).map(e => e.name).filter(Boolean);
  const images = Array.isArray(ex.images) ? ex.images.map(i => i.image).filter(Boolean) : [];
  let out = name + ' [#' + ex.id + ']\n';
  out += 'Category: ' + cat + '\n';
  if (aliases.length) out += 'Also known as: ' + aliases.join(', ') + '\n';
  if (equip.length) out += 'Equipment: ' + equip.join(', ') + '\n'; else out += 'Equipment: bodyweight\n';
  if (primary.length) out += 'Primary muscles: ' + primary.join(', ') + '\n';
  if (secondary.length) out += 'Secondary muscles: ' + secondary.join(', ') + '\n';
  if (desc) {
    const trimmed = desc.length > 1500 ? desc.substring(0, 1500) + '... (truncated)' : desc;
    out += '\nDescription:\n' + trimmed + '\n';
  }
  if (images.length) {
    out += '\nImages (' + images.length + '): ' + images.slice(0, 3).join(' | ');
    if (images.length > 3) out += ' ...';
    out += '\n';
  }
  return out.trim();
}

try {
  if (action === 'search_exercises') {
    const langId = langCode(input.language);
    const limit = Math.min(Math.max(parseInt(input.limit) || 10, 1), 50);
    let qs = '?language=' + langId + '&limit=' + limit;
    if (input.muscles) qs += '&muscles=' + encodeURIComponent(String(input.muscles));
    if (input.equipment) qs += '&equipment=' + encodeURIComponent(String(input.equipment));
    if (input.category) qs += '&category=' + encodeURIComponent(String(input.category));
    const data = await api('/exerciseinfo/' + qs);
    const results = (data && data.results) || [];
    if (input.name) {
      const needle = String(input.name).toLowerCase();
      results.sort((a, b) => {
        const an = ((pickTranslation(a.translations, langId) || {}).name || '').toLowerCase();
        const bn = ((pickTranslation(b.translations, langId) || {}).name || '').toLowerCase();
        const aHit = an.includes(needle) ? 0 : 1;
        const bHit = bn.includes(needle) ? 0 : 1;
        return aHit - bHit;
      });
    }
    if (results.length === 0) return [{ json: { result: 'No exercises found for the given filters.' } }];
    let out = 'Found ' + (data.count || results.length) + ' exercises (showing ' + results.length + '):\n\n';
    for (let i = 0; i < results.length; i++) out += formatExerciseSummary(results[i], langId, i) + '\n\n';
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out.trim() } }];
  }

  if (action === 'get_exercise') {
    const id = parseInt(input.exercise_id);
    if (!id) return [{ json: { error: 'Parameter "exercise_id" is required (integer ID from search_exercises).' } }];
    const langId = langCode(input.language);
    const ex = await api('/exerciseinfo/' + id + '/');
    if (!ex || !ex.id) return [{ json: { error: 'Exercise ' + id + ' not found.' } }];
    return [{ json: { result: formatExerciseFull(ex, langId) } }];
  }

  if (action === 'list_categories') {
    const data = await api('/exercisecategory/?limit=100');
    const items = (data && data.results) || [];
    let out = 'Exercise categories (' + items.length + '):\n';
    for (const c of items) out += '  ' + c.id + ': ' + c.name + '\n';
    return [{ json: { result: out.trim() } }];
  }

  if (action === 'list_muscles') {
    const data = await api('/muscle/?limit=100');
    const items = (data && data.results) || [];
    let out = 'Muscles (' + items.length + '):\n';
    for (const m of items) {
      const en = m.name_en || m.name;
      const lat = m.name && m.name !== en ? ' (' + m.name + ')' : '';
      const front = m.is_front ? 'front' : 'back';
      out += '  ' + m.id + ': ' + en + lat + ' [' + front + ']\n';
    }
    return [{ json: { result: out.trim() } }];
  }

  if (action === 'list_equipment') {
    const data = await api('/equipment/?limit=100');
    const items = (data && data.results) || [];
    let out = 'Equipment (' + items.length + '):\n';
    for (const e of items) out += '  ' + e.id + ': ' + e.name + '\n';
    return [{ json: { result: out.trim() } }];
  }

  if (action === 'list_public_templates') {
    const limit = Math.min(Math.max(parseInt(input.limit) || 20, 1), 50);
    const data = await api('/public-templates/?limit=' + limit);
    const items = (data && data.results) || [];
    if (items.length === 0) return [{ json: { result: 'No public workout templates available.' } }];
    let out = 'Public workout templates (' + (data.count || items.length) + ', showing ' + items.length + '):\n\n';
    for (let i = 0; i < items.length; i++) {
      const t = items[i];
      out += (i + 1) + '. ' + (t.name || 'Untitled') + ' [#' + t.id + ']';
      if (t.description) out += ' — ' + stripHtml(t.description).substring(0, 120);
      out += '\n';
      if (t.start && t.end) out += '   Duration: ' + t.start + ' to ' + t.end + '\n';
      out += '\n';
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out.trim() } }];
  }

  if (action === 'get_template_detail') {
    const id = parseInt(input.template_id);
    if (!id) return [{ json: { error: 'Parameter "template_id" is required (integer ID from list_public_templates).' } }];
    const t = await api('/public-templates/' + id + '/');
    if (!t || !t.id) return [{ json: { error: 'Template ' + id + ' not found.' } }];
    let out = (t.name || 'Untitled') + ' [#' + t.id + ']\n';
    if (t.description) out += stripHtml(t.description) + '\n';
    if (t.start && t.end) out += 'Duration: ' + t.start + ' to ' + t.end + '\n';
    if (Array.isArray(t.days) && t.days.length) {
      out += '\nSessions:\n';
      for (const d of t.days) {
        out += '  Day: ' + (d.description || 'Workout') + (d.is_rest ? ' (rest day)' : '') + '\n';
        if (Array.isArray(d.slots)) {
          for (const s of d.slots) {
            const exId = s.exercise || (s.exercises && s.exercises[0]) || '?';
            out += '    - Exercise #' + exId;
            if (s.config && s.config.length) {
              const cfg = s.config[0];
              if (cfg.sets) out += ' | sets: ' + cfg.sets;
              if (cfg.reps) out += ' | reps: ' + cfg.reps;
              if (cfg.weight) out += ' | weight: ' + cfg.weight;
            }
            out += '\n';
          }
        }
      }
    }
    if (out.length > 5000) out = out.substring(0, 5000) + '\n... (truncated)';
    return [{ json: { result: out.trim(), raw: { id: t.id, name: t.name, days: t.days || [] } } }];
  }

  return [{ json: { error: 'Unknown action: ' + action + '. Available: search_exercises, get_exercise, list_categories, list_muscles, list_equipment, list_public_templates, get_template_detail.' } }];
} catch (err) {
  return [{ json: { error: 'wger API call failed: ' + (err.message || String(err)) } }];
}
